@app.middleware("http")
async def idempotency_check(request, call_next):
    key = request.headers.get("Idempotency-Key")
    if key:
        cached = await db.fetchrow(
            "SELECT * FROM idempotency WHERE key=$1", key)
        if cached:
            return JSONResponse(cached['response_body'], cached['response_status'])
    resp = await call_next(request)
    if key and resp.status_code in (200, 201, 202):
        await db.execute("INSERT INTO idempotency ...")
    return resp
